// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAXN 500005
#define MAXQ 500005
int N, Q, L, R;
int arr[MAXN];
int tree[4 * MAXN];
void build(int node, int start, int end) {
    if (start == end) {
        tree[node] = arr[start];
    } else {
        int mid = (start + end) / 2;
        build(2 * node, start, mid);
        build(2 * node + 1, mid + 1, end);
        tree[node] = (tree[2 * node] > tree[2 * node + 1]) ? tree[2 * node] : tree[2 * node + 1];
    }
}
int query(int node, int start, int end, int l, int r) {
    if (r < start || end < l) {
        return 0;
    }
    if (l <= start && end <= r) {
        return tree[node];
    }
    int mid = (start + end) / 2;
    int p1 = query(2 * node, start, mid, l, r);
    int p2 = query(2 * node + 1, mid + 1, end, l, r);
    return (p1 > p2) ? p1 : p2;
}
void update(int node, int start, int end, int idx, int val) {
    if (start == end) {
        tree[node] = val;
    } else {
        int mid = (start + end) / 2;
        if (idx <= mid) {
            update(2 * node, start, mid, idx, val);
        } else {
            update(2 * node + 1, mid + 1, end, idx, val);
        }
        tree[node] = (tree[2 * node] > tree[2 * node + 1]) ? tree[2 * node] : tree[2 * node + 1];
    }
}
int countSubarrays(int l, int r) {
    int count = 0;
    for (int i = l; i <= r; i++) {
        int maxVal = 0;
        for (int j = i; j <= r; j++) {
            maxVal = (maxVal > arr[j]) ? maxVal : arr[j];
            if (maxVal >= L && maxVal <= R) {
                count++;
            }
        }
    }
    return count;
}
int main() {
    scanf("%d %d %d %d", &N, &Q, &L, &R);
    for (int i = 1; i <= N; i++) {
        arr[i] = 0;
    }
    build(1, 1, N);
    for (int i = 1; i <= Q; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int x, y;
            scanf("%d %d", &x, &y);
            arr[x] = y;
            update(1, 1, N, x, y);
        } else {
            int l, r;
            scanf("%d %d", &l, &r);
            printf("%d\n", countSubarrays(l, r));
        }
    }
    return 0;
}

